inue else: end_time = get_time() end_num = int(end_time[0:2]) sum = end_num - start_num sum = sum if(sum&gt;=0) else sum+24 sum = sum+1 if(sum==0) else sum print(&#34;已下机！下机时间为：&#34;+end_time+&#34;
